mapper.select:
select f.`code`, f.`name`, f.type, f.domain, f.path, f.suffix, concat(#{localFilePath,jdbcType=VARCHAR}, f.code) as url, f.source, f.size, f.create_time, u.nickname as create_by from file f left join `user` u on f.create_by = u.id
and f.type = #{param.type,jdbcType=INTEGER}
AND f.name LIKE CONCAT('%',#{param.name,jdbcType=VARCHAR},'%')
and f.source = #{param.source,jdbcType=INTEGER}
AND f.create_by = #{param.userId,jdbcType=INTEGER}
and f.del_flag = 0
order by f.create_time desc
